SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Table structure for product_process_unit_prices
-- ----------------------------
DROP TABLE IF EXISTS `product_process_unit_prices`;
CREATE TABLE `product_process_unit_prices`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主キー',
  `product_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '製品CD',
  `route_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'ルートCD',
  `step_no` int NOT NULL COMMENT 'ステップ番号',
  `line_seq` int NOT NULL DEFAULT 1 COMMENT '行連番 (同ステップ内)',
  `line_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT 'process' COMMENT '種別 (material/process/other)',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '内容説明',
  `increment_unit_price` decimal(18, 6) NOT NULL DEFAULT 0.000000 COMMENT '増分単価',
  `currency` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT 'JPY' COMMENT '通貨',
  `effective_from` date NULL DEFAULT NULL COMMENT '有効開始日',
  `effective_to` date NULL DEFAULT NULL COMMENT '有効終了日 (NULL=無期限)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT 'active' COMMENT '状態',
  `bom_line_id` int NULL DEFAULT NULL COMMENT '参照BOM行ID (追跡用)',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL COMMENT '備考',
  `created_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '作成者',
  `updated_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '更新者',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_price_product_route`(`product_cd` ASC, `route_cd` ASC) USING BTREE,
  INDEX `idx_price_effective`(`product_cd` ASC, `route_cd` ASC, `effective_from` ASC, `effective_to` ASC) USING BTREE,
  INDEX `idx_price_step`(`product_cd` ASC, `route_cd` ASC, `step_no` ASC, `line_seq` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 694 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin COMMENT = '工程別標準原価増分' ROW_FORMAT = Dynamic;

